mapper.insert:
INSERT  INTO TB_PROGRM_CHANGE_DTLS
      ( PROGRM_FILE_NM
      , REQUST_NO
      , RQESTER_ID
      , CHANGE_REQUST_CN
      , REQUST_DE
      , REQUST_SJ
      , PROCESS_STTUS_CODE )
VALUES  ( #{progrmFileNm}
        , #{rqesterNo}
        , #{rqesterPersonId}
        , #{changerqesterCn}
        , TO_DATE(#{rqesterDe}, 'yyyy-mm-dd')
        , #{rqesterSj}
        , 'A' )

mapper.update:
UPDATE  TB_PROGRM_CHANGE_DTLS
   SET  RQESTER_ID = #{rqesterPersonId}
      , CHANGE_REQUST_CN = #{changerqesterCn}
      , REQUST_DE = TO_DATE(#{rqesterDe}, 'yyyy-mm-dd')
      , REQUST_SJ = #{rqesterSj}
 WHERE  PROGRM_FILE_NM = #{progrmFileNm}
   AND  REQUST_NO = #{rqesterNo}

mapper.delete:
DELETE
  FROM  TB_PROGRM_CHANGE_DTLS
 WHERE  PROGRM_FILE_NM = #{progrmFileNm}
   AND  REQUST_NO = #{rqesterNo}

mapper.update:
UPDATE  TB_PROGRM_CHANGE_DTLS
   SET  REQUST_PROCESS_CN = #{rqesterProcessCn}
      , OPETR_ID = #{opetrId}
      , PROCESS_STTUS_CODE = #{processSttus}
      , PROCESS_DE = TO_DATE(#{processDe}, 'yyyy-mm-dd')
 WHERE  PROGRM_FILE_NM = #{progrmFileNm}
   AND  REQUST_NO = #{rqesterNo}

mapper.select:
SELECT * /* TODO: 컬럼 명시 필요 */ FROM ( SELECT ROWNUM RN , TB.* /* TODO: 컬럼 명시 필요 */ FROM ( SELECT PROGRM_FILE_NM AS "progrmFileNm" , REQUST_NO AS "rqesterNo" , RQESTER_ID AS "rqesterPersonId" , DBMS_LOB.SUBSTR(CHANGE_REQUST_CN, 10, 1) || '...' AS "changerqesterCn" , DBMS_LOB.SUBSTR(REQUST_PROCESS_CN, 10, 1) || '...' AS "rqesterProcessCn" , OPETR_ID AS "opetrId" , TRIM(PROCESS_STTUS_CODE) AS "processSttus" , TO_CHAR(PROCESS_DE, 'YYYY-MM-DD') AS "processDe" , TO_CHAR(REQUST_DE, 'YYYY-MM-DD') AS "rqesterDe" , REQUST_SJ AS "rqesterSj" FROM TB_PROGRM_CHANGE_DTLS WHERE 1 = 1
AND PROCESS_STTUS_CODE LIKE #{searchKeyword}
AND PROCESS_STTUS_CODE = #{searchKeyword}
AND TO_CHAR(REQUST_DE, 'YYYY-MM-DD') BETWEEN #{searchKeywordFrom} AND #{searchKeywordTo}
AND RQESTER_ID LIKE '%' || #{searchKeyword} || '%'
ORDER BY REQUST_NO ASC ) TB ) WHERE RN BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

SELECT  COUNT(REQUST_NO) AS "totcnt"
  FROM  TB_PROGRM_CHANGE_DTLS
 WHERE  1 = 1

   AND  PROCESS_STTUS_CODE LIKE #{searchKeyword}


   AND  PROCESS_STTUS_CODE = #{searchKeyword}


   AND  TO_CHAR(REQUST_DE, 'YYYY-MM-DD') BETWEEN #{searchKeywordFrom} AND #{searchKeywordTo}


   AND  RQESTER_ID LIKE '%' || #{searchKeyword} || '%'

SELECT  USER_EMAIL AS "tmp_Email"
  FROM  VW_USER_MASTER
 WHERE  USER_ID = #{rqesterPersonId}
